<?php

namespace App\Http\Controllers;

use App\Models\Subscription;
use App\Models\Package;
use App\Models\TimeSubscription;
use App\Models\PackagePayment;
use App\Models\User;
use Illuminate\Http\Request;

class SubscriptionController extends Controller
{
    public function __construct()
    {
        $this->middleware('auth:sanctum');
    }

    public function index(Request $request)
    {
        return response()->json($request->user()->subscriptions()->with('package')->get());
    }

    public function active(Request $request)
    {
        $subscription = $request->user()->subscriptions()
            ->where('status', 'active')
            ->with('package')
            ->latest()
            ->first();

        return response()->json($subscription);
    }

    public function store(Request $request)
    {
        $validated = $request->validate([
            'package_id' => 'required|string',
            'time_subscription_id' => 'nullable|string',
            'payment_method' => 'required|string',
            'amount' => 'nullable|numeric|min:0',
            'duration_months' => 'nullable|integer|in:1,3,12',
        ]);

        $package = Package::findOrFail($validated['package_id']);

        $hasActiveSubscription = $request->user()->subscriptions()
            ->where('status', 'active')
            ->exists();

        if ($hasActiveSubscription) {
            return response()->json(['message' => 'Bạn đã có gói đang hoạt động.'], 400);
        }

        if ($package->is_trial) {
            $hasUsedTrial = $request->user()->subscriptions()
                ->whereHas('package', fn($q) => $q->where('is_trial', true))
                ->exists();

            if ($hasUsedTrial) {
                return response()->json(['message' => 'Bạn đã sử dụng gói dùng thử trước đó.'], 400);
            }
        }

        $startDate = now();
        $timeSub = null;

        if ($package->is_trial) {
            $endDate = $startDate->copy()->addDays(7);
        } elseif (!empty($validated['time_subscription_id'])) {
            $timeSub = TimeSubscription::findOrFail($validated['time_subscription_id']);
            $durationValue = $timeSub->duration_value;
            $durationUnit = $timeSub->duration_unit;
            $endDate = $durationUnit === 'day'
                ? $startDate->copy()->addDays($durationValue)
                : $startDate->copy()->addMonths($durationValue);
        } elseif (!empty($validated['duration_months'])) {
            $endDate = $startDate->copy()->addMonths((int) $validated['duration_months']);
        } else {
            $endDate = $startDate->copy()->addMonths(1);
        }

        $now = now();

        $subscription = $request->user()->subscriptions()->create([
            'package_id' => (string) $package->id,
            'time_subscription_id' => $timeSub ? (string) $timeSub->id : null,
            'package_name_snapshot' => $package->name,
            'package_code_snapshot' => $package->type ?? $package->code ?? 'free',
            'start_date' => $startDate,
            'end_date' => $endDate,
            'subtotal' => $validated['amount'] ?? 0,
            'total_amount' => $validated['amount'] ?? 0,
            'status' => 'active',
        ]);

        $todayStr = $now->format('Ymd');
        $paymentCount = PackagePayment::where('transaction_code', 'like', "TXN-{$todayStr}-%")->count() + 1;
        $txnCode = 'TXN-' . $todayStr . '-' . str_pad($paymentCount, 4, '0', STR_PAD_LEFT);

        $subscription->packagePayments()->create([
            'user_id' => (string) $request->user()->id,
            'package_id' => (string) $package->id,
            'time_subscription_id' => $timeSub ? (string) $timeSub->id : null,
            'amount' => $validated['amount'] ?? (float) ($package->price ?? 0),
            'payment_method' => $validated['payment_method'],
            'payment_status' => 'paid',
            'transaction_code' => $txnCode,
            'paid_at' => $now,
        ]);

        return response()->json($subscription->load('package'), 201);
    }
}
