              topping: { id: t.toppingId, name: t.toppingNameSnapshot, price: t.priceAtTime, isAvailable: true },
              quantity: t.quantity,
            })),
            note: oi.note ?? '',
          }));
        }
        setDraftOrderIds(draftMap);
        setCarts(cartsFromOrders);
      }),
    ]).catch(() => showToast('Không thể tải dữ liệu')).finally(() => setLoading(false));
  }, []);

