public function store(Request $request, Cafe $cafe)
{
    $validated = $request->validate([
        'order_id' => 'required|string',
        'invoice_id' => 'required|string',
        'review_code' => 'required|string',
        'customer_name' => 'nullable|string|max:255',
        'customer_phone' => 'nullable|string|max:20',
        'overall_rating' => 'required|integer|min:1|max:5',
        'drink_rating' => 'nullable|integer|min:1|max:5',
        'service_rating' => 'nullable|integer|min:1|max:5',
        'space_rating' => 'nullable|integer|min:1|max:5',
        'comment' => 'nullable|string|max:2000',
    ]);

    // BUG-05 FIX: Kiểm tra invoice tồn tại và đúng review_code
    $invoice = Invoice::where('_id', $validated['invoice_id'])
        ->where('review_code', $validated['review_code'])
        ->where('cafe_id', (string) $cafe->id)
        ->first();

    if (!$invoice) {
        return response()->json(['message' => 'Mã đánh giá không hợp lệ.'], 404);
    }

    // BUG-05 FIX: Chặn gửi review trùng lặp
    if ($invoice->has_review) {
        return response()->json(['message' => 'Hóa đơn này đã được đánh giá.'], 400);
    }

    $reviewCode = 'RVW-' . now()->format('Ymd') . '-' . strtoupper(bin2hex(random_bytes(4)));

    $review = $cafe->reviews()->create($validated + [
        'review_code' => $reviewCode,
        'status' => 'visible',
    ]);

    $invoice->update(['has_review' => true]);

    return response()->json($review, 201);
}

