     4→export class ApiError extends Error {
     5→  status: number;
     6→  errors?: Record<string, string[]>;
     7→
     8→  constructor(message: string, status: number, errors?: Record<string, string[]>) {
     9→    super(message);
    10→    this.status = status;
    11→    this.errors = errors;
    12→  }
    13→}
