    15→function getToken(): string | null {
    16→  if (typeof window === 'undefined') return null;
    17→  return localStorage.getItem('funcafe_token');
    18→}
    19→
    20→function setToken(token: string) {
    21→  localStorage.setItem('funcafe_token', token);
    22→}
    23→
    24→function removeToken() {
    25→  localStorage.removeItem('funcafe_token');
    26→}
    27→
    28→async function request<T>(endpoint: string, options: RequestInit = {}): Promise<T> {
    29→  const token = getToken();
    30→  const headers: Record<string, string> = {
    31→    Accept: 'application/json',
    32→    'Content-Type': 'application/json',
    33→    ...((options.headers as Record<string, string>) || {}),
    34→  };
    35→
    36→  if (token) {
    37→    headers.Authorization = `Bearer ${token}`;
    38→  }
    39→
    40→  const url = `${API_BASE}${endpoint}`;
    41→  const response = await fetch(url, { ...options, headers });
    42→
    43→  if (!response.ok) {
    44→    const body = await response.json().catch(() => ({}));
    45→    throw new ApiError(
    46→      body.message || `HTTP ${response.status}`,
    47→      response.status,
    48→      body.errors,
    49→    );
    50→  }
    51→
    52→  return response.json();
    53→}
    54→
    55→export const api = {
    56→  get: <T>(endpoint: string) => request<T>(endpoint),
    57→  post: <T>(endpoint: string, data?: unknown) =>
    58→    request<T>(endpoint, { method: 'POST', body: JSON.stringify(data) }),
    59→  put: <T>(endpoint: string, data?: unknown) =>
    60→    request<T>(endpoint, { method: 'PUT', body: JSON.stringify(data) }),
    61→  delete: <T>(endpoint: string) =>
    62→    request<T>(endpoint, { method: 'DELETE' }),
    63→  setToken,
    64→  getToken,
    65→  removeToken,
    66→  upload: async (file: File): Promise<string> => {
    67→    const formData = new FormData();
    68→    formData.append('file', file);
    69→    const token = getToken();
    70→    const response = await fetch(`${API_BASE}/upload`, {
    71→      method: 'POST',
    72→      headers: token ? { Authorization: `Bearer ${token}` } : {},
    73→      body: formData,
    74→    });
    75→    if (!response.ok) throw new ApiError('Upload thất bại', response.status);
    76→    const data = await response.json();
    77→    return `${STORAGE_URL}${data.url}`;
    78→  },
    79→};
