    const d = date.slice(0, 10);
    groups[d] = (groups[d] ?? 0) + inv.totalAmount;
  });
  return Object.entries(groups).sort(([a], [b]) => a.localeCompare(b)).map(([k, v]) => ({
    month: k.slice(5), revenue: v,
  }));
}

