    const date = inv.paidAt || inv.createdAt;
    const y = date.slice(0, 4);
    groups[y] = (groups[y] ?? 0) + inv.totalAmount;
  });
  return Object.entries(groups).sort(([a], [b]) => a.localeCompare(b)).map(([k, v]) => ({
