     2→import { createContext, useContext, useState, useCallback, useEffect, type ReactNode } from 'react';
     3→import { api, type AuthUser, type AuthResponse, type SubscriptionData } from '@/lib/api-client';
     4→
     5→export interface UserSubscription {
     6→  packageType: 'none' | 'free' | 'pro' | 'promax';
     7→  packageName: string;
     8→  startDate: string;
     9→  endDate: string;
    10→  daysLeft: number;
    11→}
    12→
    13→export interface CurrentUser {
    14→  id: string;
    15→  fullName: string;
    16→  email: string;
    17→  phone: string;
    18→  role: 'user' | 'admin';
    19→  subscription: UserSubscription;
    20→}
    21→
    22→interface AuthContextType {
    23→  user: CurrentUser | null;
    24→  isLoading: boolean;
    25→  isAuthenticated: boolean;
    26→  login: (email: string, password: string) => Promise<'user' | 'admin'>;
    27→  register: (data: { fullName: string; email: string; phone: string; password: string }) => Promise<'user' | 'admin'>;
    28→  logout: () => void;
    29→  refreshUser?: () => Promise<void>;
    30→}
    31→
    32→function mapSubscription(subs: SubscriptionData[]): UserSubscription {
    33→  const active = subs.find((s) => s.status === 'active');
    34→  if (!active) {
    35→    return { packageType: 'none', packageName: 'Chưa đăng ký', startDate: '', endDate: '', daysLeft: 0 };
    36→  }
    37→  const start = new Date(active.start_date);
    38→  const end = new Date(active.end_date);
    39→  const daysLeft = Math.max(0, Math.ceil((end.getTime() - Date.now()) / 86400000));
    40→  return {
    41→    packageType: (active.package?.type as UserSubscription['packageType']) || 'free',
    42→    packageName: active.package?.name || 'Free',
    43→    startDate: active.start_date,
    44→    endDate: active.end_date,
    45→    daysLeft,
    46→  };
    47→}
    48→
    49→function mapUser(u: AuthUser, subs: SubscriptionData[]): CurrentUser {
    50→  return {
    51→    id: u._id,
    52→    fullName: u.full_name,
    53→    email: u.email,
    54→    phone: u.phone || '',
    55→    role: u.role === 'admin' ? 'admin' : 'user',
    56→    subscription: mapSubscription(subs),
    57→  };
    58→}
    59→
    60→async function fetchSubscriptions(): Promise<SubscriptionData[]> {
    61→  try {
    62→    return await api.get<SubscriptionData[]>('/subscriptions');
    63→  } catch {
    64→    return [];
    65→  }
    66→}
    67→
    68→const AuthContext = createContext<AuthContextType | null>(null);
    69→
    70→export function AuthProvider({ children }: { children: ReactNode }) {
    71→  const [user, setUser] = useState<CurrentUser | null>(null);
    72→  const [isLoading, setIsLoading] = useState(true);
    73→
    74→  useEffect(() => {
    75→    const token = api.getToken();
    76→    if (!token) {
    77→      setIsLoading(false);
    78→      return;
    79→    }
    80→    api.get<AuthUser>('/user')
    81→      .then(async (u) => {
    82→        const subs = await fetchSubscriptions();
    83→        setUser(mapUser(u, subs));
    84→      })
    85→      .catch(() => {
    86→        api.removeToken();
    87→      })
    88→      .finally(() => setIsLoading(false));
    89→  }, []);
    90→
    91→  const login = useCallback(async (email: string, password: string): Promise<'user' | 'admin'> => {
    92→    setIsLoading(true);
    93→    try {
    94→      const res = await api.post<AuthResponse>('/auth/login', { email, password });
    95→      api.setToken(res.token);
    96→      const subs = await fetchSubscriptions();
    97→      const user = mapUser(res.user, subs);
    98→      setUser(user);
    99→      return user.role;
   100→    } catch (error) {
   101→      throw error;
   102→    } finally {
   103→      setIsLoading(false);
   104→    }
   105→  }, []);
   106→
   107→  const register = useCallback(async (data: { fullName: string; email: string; phone: string; password: string }): Promise<'user' | 'admin'> => {
   108→    setIsLoading(true);
   109→    try {
   110→      const res = await api.post<AuthResponse>('/auth/register', {
   111→        full_name: data.fullName,
   112→        email: data.email,
   113→        phone: data.phone,
   114→        password: data.password,
   115→      });
   116→      api.setToken(res.token);
   117→      const subs = await fetchSubscriptions();
   118→      const user = mapUser(res.user, subs);
   119→      setUser(user);
   120→      return user.role;
   121→    } catch (error) {
   122→      throw error;
   123→    } finally {
   124→      setIsLoading(false);
   125→    }
   126→  }, []);
   127→
   128→  const logout = useCallback(async () => {
   129→    try {
   130→      await api.post('/auth/logout');
   131→    } catch {
   132→      // ignore
   133→    }
   134→    api.removeToken();
   135→    // BUG-15 FIX: Xóa cafeIdCache khi đăng xuất tránh dùng cache của user cũ
   136→    const { clearCafeCache } = await import('@/services');
   137→    clearCafeCache();
   138→    setUser(null);
   139→  }, []);
   140→
   141→  const refreshUser = useCallback(async () => {
   142→    const token = api.getToken();
   143→    if (!token) return;
   144→    try {
   145→      const u = await api.get<AuthUser>('/user');
   146→      const subs = await fetchSubscriptions();
   147→      setUser(mapUser(u, subs));
   148→    } catch {
   149→      api.removeToken();
   150→      setUser(null);
   151→    }
   152→  }, []);
   153→
   154→  return (
   155→    <AuthContext.Provider value={{ user, isLoading, isAuthenticated: user !== null, login, register, logout, refreshUser }}>
   156→      {children}
   157→    </AuthContext.Provider>
   158→  );
   159→}
   160→
   161→export function useAuth() {
   162→  const ctx = useContext(AuthContext);
   163→  if (!ctx) throw new Error('useAuth must be used within AuthProvider');
   164→  return ctx;
   165→}
